import React from "react";
import moment from "moment";
import Layout from "../../layouts/default";
import PageHeader from "../../components/PageHeader";
import PageContent from "../../components/PageContent";
import Loader from "../../components/Loader";
import UserCard from "../../components/UserCard";
import Link from "../../components/Link";
import fetchMembers from "../../utils/fetchMembers";

let cachedModerators, cachedSupportStaff;

export default class Members extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      moderators: [],
      supportStaff: [],
    };
  }

  componentDidMount() {
    if (cachedModerators) {
      this.setState({
        moderators: cachedModerators
      });
    } else {
      fetchMembers("moderators").then(fetchedModerators => {
        cachedModerators = fetchedModerators;

        this.setState({
          moderators: fetchedModerators
        });
      }).catch(console.error);
    }

    if (cachedSupportStaff) {
      this.setState({
        supportStaff: cachedSupportStaff
      });
    } else {
      fetchMembers("support").then(fetchedSupportStaff => {
        cachedSupportStaff = fetchedSupportStaff;

        this.setState({
          supportStaff: fetchedSupportStaff
        });
      }).catch(console.error);
    }
  }

  render () {
    return (
      <Layout
        title="Members"
        description="These are the cool and amazing members of Bastion HQ Discord Server. These are the people who keep the Discord server running in equilibrium."
        image=""
      >
        <PageHeader title="Members">
          <p>
            The cool and amazing members of Bastion HQ Discord Server. These
            are the people who keep the Discord server running in equilibrium.
          </p>
          <p>
            If you also want to be a part of this amazing team and help us
            keep the Discord server running, contact us in Bastion HQ.
          </p>
        </PageHeader>

        <PageContent>
          {
            this.state.moderators.length
            ? this.state.moderators.map((user, i) => (
                <UserCard
                  title={ user.tag }
                  description="Moderator"
                  image={ user.avatar }
                  key={ i }
                />
              ))
            : <></>
          }
          {
            this.state.supportStaff.length
            ? this.state.supportStaff.map((user, i) => (
                <UserCard
                  title={ user.tag }
                  description="Support Staff"
                  image={ user.avatar }
                  key={ i }
                />
              ))
            : <></>
          }
          {
            this.state.moderators.length && this.state.supportStaff.length
            ? <></>
            : <Loader />
          }
        </PageContent>
      </Layout>
    );
  }
}
